ALTER TABLE `Users` MODIFY `email` varchar(160) COLLATE utf8mb4_unicode_ci DEFAULT NULL;
UPDATE `Users` SET `phone` = CONCAT('62', `id`) WHERE `phone` IS NULL OR TRIM(`phone`) = '';
UPDATE `Users` SET `phone` = REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(`phone`, '+', ''), ' ', ''), '-', ''), '.', ''), '(', '');
UPDATE `Users` SET `phone` = REPLACE(`phone`, ')', '');
UPDATE `Users` SET `phone` = CASE WHEN `phone` LIKE '0%' THEN CONCAT('62', SUBSTRING(`phone`, 2)) WHEN `phone` NOT LIKE '62%' THEN CONCAT('62', `phone`) ELSE `phone` END;
ALTER TABLE `Users` MODIFY `phone` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL;
ALTER TABLE `Users` ADD UNIQUE KEY `uniq_users_phone` (`phone`);
ALTER TABLE `ReportHeavyEquipmentUsages` ADD COLUMN `volume` varchar(60) COLLATE utf8mb4_unicode_ci DEFAULT NULL AFTER `quantity`;
ALTER TABLE `ReportHeavyEquipmentUsages` ADD COLUMN `unit` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT 'unit' AFTER `volume`;
CREATE TABLE IF NOT EXISTS `ReportRealizationItems` (`id` bigint unsigned NOT NULL AUTO_INCREMENT, `daily_report_id` bigint unsigned NOT NULL, `work_item` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL, `unit` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `plan_text` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `realization_text` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `deviation_text` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `partner` varchar(160) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `sort_order` int NOT NULL DEFAULT '0', `created_at` datetime DEFAULT NULL, `updated_at` datetime DEFAULT NULL, PRIMARY KEY (`id`), KEY `idx_report_realization_report` (`daily_report_id`), CONSTRAINT `fk_report_realization_report` FOREIGN KEY (`daily_report_id`) REFERENCES `DailyReports` (`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE TABLE IF NOT EXISTS `ReportLightToolUsages` (`id` bigint unsigned NOT NULL AUTO_INCREMENT, `daily_report_id` bigint unsigned NOT NULL, `tool_label` varchar(160) COLLATE utf8mb4_unicode_ci NOT NULL, `volume` varchar(60) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `unit` varchar(40) COLLATE utf8mb4_unicode_ci DEFAULT NULL, `sort_order` int NOT NULL DEFAULT '0', `created_at` datetime DEFAULT NULL, `updated_at` datetime DEFAULT NULL, PRIMARY KEY (`id`), KEY `idx_report_light_tool_report` (`daily_report_id`), CONSTRAINT `fk_report_light_tool_report` FOREIGN KEY (`daily_report_id`) REFERENCES `DailyReports` (`id`) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
